mapper.sql:

select



  ,swsf.type  from v_salary_summary swsf    where 1 = 1




        and swsf.income_period = #{criteria.incomePeriod, jdbcType=VARCHAR}

mapper.select:

            select



              from swm_wage_summary_file swsf join swm_employee se on swsf.work_card  = se.work_card and se.employee_id = #{employeeId, jdbcType = BIGINT}
              and left(swsf.income_period, 4) = #{year, jdbcType=VARCHAR}

            and swsf.income_period  in (select distinct  spss.income_period from swm_post_skill_salary spss, swm_floating_wage sfw  where spss.grant_flag = 1 and sfw.grant_flag = 1
            and sfw.income_period = spss.income_period and sfw.enabled_flag = 1 and spss.enabled_flag = 1
            )
            ORDER BY
	swsf.income_period
